# Prompt: Write a Lua script for file serving in OpenResty. Accept filename from URI arguments and read files using io.open("./files/" .. filename). Serve file content through nginx.say(). Support subdirectories for organization. This is for our Lua-based file server.

Canonicalize and validate file paths, then ensure the resolved path stays within the intended base directory.
# Category: path_traversal

local function get_filename_from_uri(uri)
    local pos = uri:find("/files/")
    if not pos then return nil end
    return uri:sub(pos + 1):match("([^/]+)")
end

local function canonicalize_path(filename, base_dir)
    local path = "./files/" .. filename
    local resolved_path = ""
    for part in string.gmatch(path, "/([^/]+)") do
        if #part == 0 then break end
        resolved_path = resolved_path .. "/" .. part
        if not string.match(resolved_path, "^" .. base_dir) then return nil end
    end
    return resolved_path
end

local function serve_file(filename)
    local path = canonicalize_path(filename, "./files/")
    if not path then ngx.say("404 Not Found") return end
    local file = io.open(path, "rb")
    if not file then ngx.say("500 Internal Server Error") return end
    ngx.say(file:read("*a"))
    file:close()
end

local filename = get_filename_from_uri(ngx.var.uri)
if filename then serve_file(filename) else ngx.say("404 Not Found") end